'use strict';

const fs = require('node:fs');
const path = require('node:path');

// Loads the sample CSV as an array of raw lines (header included, blank lines
// dropped). Field decoding is the parser's job (src/core/csv.js).

function loadRows() {
  const file = path.join(__dirname, '..', '..', 'data', 'rows.csv');
  return fs.readFileSync(file, 'utf8').split(/\r?\n/).filter((l) => l.length > 0);
}

module.exports = { loadRows };

input.command:
node -e "
const { parseCsvLine } = require('./src/core/csv.js');
const tests = [
  { input: 'a,b,c', expected: ['a','b','c'] },
  { input: '\"a,b\",c', expected: ['a,b','c'] },
  { input: '\"she said \"\"hi\"\"\"', expected: ['she said \"hi\"'] },
  { input: 'a , b', expected: ['a ',' b'] },
  { input: 'id,name,role', expected: ['id','name','role'] },
  { input: '1,alice,admin', expected: ['1','alice','admin'] },
];
let pass = 0;
for (const t of tests) {
  const got = parseCsvLine(t.input);
  const ok = JSON.stringify(got) === JSON.stringify(t.expected);
  console.log(ok ? 'PASS' : 'FAIL', JSON.stringify(t.input), '->', JSON.stringify(got), ok ? '' : 'expected ' + JSON.stringify(t.expected));
  if (ok) pass++;
}
console.log(pass + '/' + tests.length + ' passed');
" 2>&1

